  @Test
  public void toJSON_compoundFeatureNodeWithChildren()
  {
    FeatureModel model = new FeatureModel("M");
    CompoundFeatureNode parent = new CompoundFeatureNode(model);
    parent.setName("Parent");
    FeatureLeaf child1 = new FeatureLeaf(model);
    child1.setName("Child1");
    FeatureLeaf child2 = new FeatureLeaf(model);
    child2.setName("Child2");
    parent.addChildFeature(child1);
    parent.addChildFeature(child2);

    String json = model.toJSON();
    Assert.assertTrue(json.contains("\"nodeType\":\"CompoundFeatureNode\""));
    Assert.assertTrue(json.contains("\"isCompoundFeature\":true"));
    Assert.assertTrue(json.contains("\"childFeatureIds\""));
    // Verify child IDs are present
    Assert.assertTrue(json.contains(String.valueOf(child1.getId())));
    Assert.assertTrue(json.contains(String.valueOf(child2.getId())));
  }

