  @Test
  public void toJSON_plainFeatureNode()
  {
    FeatureModel model = new FeatureModel("M");
    FeatureNode node = new FeatureNode(model);
    node.setName("PlainNode");

    String json = model.toJSON();
    Assert.assertTrue(json.contains("\"nodeType\":\"FeatureNode\""));
    Assert.assertTrue(json.contains("\"isLeaf\":false"));
    Assert.assertTrue(json.contains("\"isCompoundFeature\":false"));
    // Should NOT contain subtype-specific fields
    Assert.assertFalse(json.contains("\"mixsetOrFileNode\""));
    Assert.assertFalse(json.contains("\"childFeatureIds\""));
    Assert.assertFalse(json.contains("\"fragments\""));
  }

  @Test
  public void toJSON_basicFeatureLink()
  {
    FeatureModel model = new FeatureModel("M");
    FeatureLeaf src = new FeatureLeaf(model);
    src.setName("Src");
    FeatureLeaf tgt = new FeatureLeaf(model);
    tgt.setName("Tgt");

    FeatureLink link = new FeatureLink();
    link.setSourceFeatureNode(src);
    link.setTargetFeatureNode(tgt);
    link.setFeatureConnectingOpType(FeatureConnectingOpType.Mandatory);
    link.setIsSub(true);
    link.setFeatureModel(model);

    String json = model.toJSON();
    Assert.assertTrue(json.contains("\"linkType\":\"FeatureLink\""));
    Assert.assertTrue(json.contains("\"opType\":\"Mandatory\""));
    Assert.assertTrue(json.contains("\"isSub\":true"));
    Assert.assertTrue(json.contains("\"sourceNodeId\":" + src.getId()));
    Assert.assertTrue(json.contains("\"targetNodeId\":" + tgt.getId()));
    // Basic FeatureLink should NOT have bounds
    Assert.assertFalse(json.contains("\"lowerBound\""));
  }

  @Test
  public void toJSON_multiplicityLink()
  {
    FeatureModel model = new FeatureModel("M");
    FeatureLeaf src = new FeatureLeaf(model);
    src.setName("Src");
    FeatureLeaf tgt = new FeatureLeaf(model);
    tgt.setName("Tgt");

    MultiplicityFeatureConnectingOpType multLink = new MultiplicityFeatureConnectingOpType();
    multLink.setSourceFeatureNode(src);
    multLink.setTargetFeatureNode(tgt);
    multLink.getMultiplicity().setRange("2", "5");
    multLink.setFeatureModel(model);

    String json = model.toJSON();
    Assert.assertTrue(json.contains("\"linkType\":\"MultiplicityFeatureConnectingOpType\""));
    Assert.assertTrue(json.contains("\"opType\":\"Multiplicity\""));
    Assert.assertTrue(json.contains("\"lowerBound\":2"));
    Assert.assertTrue(json.contains("\"upperBound\":5"));
  }

