  @Test
  public void toJSON_allOpTypes()
  {
    // Verify each FeatureConnectingOpType serializes its name correctly
    for (FeatureConnectingOpType opType : FeatureConnectingOpType.values())
    {
      FeatureModel model = new FeatureModel("M");
      FeatureLeaf src = new FeatureLeaf(model);
      src.setName("S");
      FeatureLeaf tgt = new FeatureLeaf(model);
      tgt.setName("T");

      FeatureLink link = new FeatureLink();
      link.setFeatureConnectingOpType(opType);
      link.setSourceFeatureNode(src);
      link.setTargetFeatureNode(tgt);
      link.setFeatureModel(model);

      String json = model.toJSON();
      Assert.assertTrue("opType " + opType.name() + " not found in JSON",
          json.contains("\"opType\":\"" + opType.name() + "\""));
    }
  }

  @Test
  public void toJSON_multipleNodesAndLinks()
  {
    FeatureModel model = new FeatureModel("Complex");
    FeatureLeaf a = new FeatureLeaf(model);
    a.setName("A");
    FeatureLeaf b = new FeatureLeaf(model);
    b.setName("B");
    CompoundFeatureNode c = new CompoundFeatureNode(model);
    c.setName("C");
    c.addChildFeature(a);
    c.addChildFeature(b);

    FeatureLink link1 = new FeatureLink();
    link1.setSourceFeatureNode(c);
    link1.setTargetFeatureNode(a);
    link1.setFeatureConnectingOpType(FeatureConnectingOpType.Mandatory);
    link1.setIsSub(true);
    link1.setFeatureModel(model);

    FeatureLink link2 = new FeatureLink();
    link2.setSourceFeatureNode(c);
    link2.setTargetFeatureNode(b);
    link2.setFeatureConnectingOpType(FeatureConnectingOpType.Optional);
    link2.setIsSub(true);
    link2.setFeatureModel(model);

    String json = model.toJSON();
    Assert.assertEquals(3, model.numberOfNode());
    Assert.assertEquals(2, model.numberOfFeaturelink());
    Assert.assertTrue(json.contains("\"name\":\"Complex\""));
    Assert.assertTrue(json.contains("\"Mandatory\""));
    Assert.assertTrue(json.contains("\"Optional\""));
  }

