  @Test
  public void fromJSON_emptyModel()
  {
    String json = "{\"featureModel\":{\"name\":\"TestModel\",\"nodes\":[],\"links\":[]}}";
    FeatureModel model = FeatureModel.fromJSON(json);
    Assert.assertNotNull(model);
    Assert.assertEquals("TestModel", model.getName());
    Assert.assertEquals(0, model.numberOfNode());
    Assert.assertEquals(0, model.numberOfFeaturelink());
  }

  @Test
  public void fromJSON_singleFeatureLeaf()
  {
    String json = "{\"featureModel\":{\"name\":\"M\",\"nodes\":[{\"id\":100,\"uniqueName\":\"LeafA\",\"name\":\"LeafA\",\"nodeType\":\"FeatureLeaf\",\"isLeaf\":true,\"isCompoundFeature\":false,\"mixsetOrFileNode\":null}],\"links\":[]}}";
    FeatureModel model = FeatureModel.fromJSON(json);
    Assert.assertNotNull(model);
    Assert.assertEquals(1, model.numberOfNode());
    FeatureNode node = model.getNode(0);
    Assert.assertTrue(node instanceof FeatureLeaf);
    Assert.assertEquals("LeafA", node.getName());
    Assert.assertEquals(100, node.getId());
    Assert.assertTrue(node.getIsLeaf());
  }

  @Test
  public void fromJSON_featureLeafWithMixset()
  {
    String json = "{\"featureModel\":{\"name\":\"M\",\"nodes\":[{\"id\":1,\"uniqueName\":\"L\",\"name\":\"L\",\"nodeType\":\"FeatureLeaf\",\"isLeaf\":true,\"isCompoundFeature\":false,\"mixsetOrFileNode\":{\"type\":\"Mixset\",\"name\":\"MixA\",\"isMixset\":true,\"isFeature\":true,\"isEmpty\":false,\"useUmpleFile\":null,\"useUmpleLine\":0}}],\"links\":[]}}";
    FeatureModel model = FeatureModel.fromJSON(json);
    FeatureLeaf leaf = (FeatureLeaf) model.getNode(0);
    Assert.assertTrue(leaf.hasMixsetOrFileNode());
    MixsetOrFile mof = leaf.getMixsetOrFileNode();
    Assert.assertTrue(mof instanceof Mixset);
    Mixset mixset = (Mixset) mof;
    Assert.assertEquals("MixA", mixset.getMixsetName());
    Assert.assertTrue(mixset.getIsFeature());
    Assert.assertFalse(mixset.getIsEmpty());
  }

  @Test
  public void fromJSON_compoundFeatureNodeWithChildren()
  {
    String json = "{\"featureModel\":{\"name\":\"M\",\"nodes\":["
        + "{\"id\":10,\"uniqueName\":\"Child1\",\"name\":\"Child1\",\"nodeType\":\"FeatureLeaf\",\"isLeaf\":true,\"isCompoundFeature\":false,\"mixsetOrFileNode\":null},"
        + "{\"id\":11,\"uniqueName\":\"Child2\",\"name\":\"Child2\",\"nodeType\":\"FeatureLeaf\",\"isLeaf\":true,\"isCompoundFeature\":false,\"mixsetOrFileNode\":null},"
        + "{\"id\":12,\"uniqueName\":\"Parent_12\",\"name\":\"Parent\",\"nodeType\":\"CompoundFeatureNode\",\"isLeaf\":false,\"isCompoundFeature\":true,\"childFeatureIds\":[10,11]}"
        + "],\"links\":[]}}";
    FeatureModel model = FeatureModel.fromJSON(json);
    Assert.assertEquals(3, model.numberOfNode());

    // Find CompoundFeatureNode
    CompoundFeatureNode parent = null;
    for (FeatureNode n : model.getNode())
    {
      if (n instanceof CompoundFeatureNode) { parent = (CompoundFeatureNode) n; }
    }
    Assert.assertNotNull(parent);
    Assert.assertEquals("Parent", parent.getName());
    Assert.assertEquals(2, parent.numberOfChildFeatures());
  }

