  @Test
  public void fromJSON_multipleLinks()
  {
    String json = "{\"featureModel\":{\"name\":\"M\",\"nodes\":["
        + "{\"id\":1,\"uniqueName\":\"A\",\"name\":\"A\",\"nodeType\":\"FeatureLeaf\",\"isLeaf\":true,\"isCompoundFeature\":false,\"mixsetOrFileNode\":null},"
        + "{\"id\":2,\"uniqueName\":\"B\",\"name\":\"B\",\"nodeType\":\"FeatureLeaf\",\"isLeaf\":true,\"isCompoundFeature\":false,\"mixsetOrFileNode\":null},"
        + "{\"id\":3,\"uniqueName\":\"C\",\"name\":\"C\",\"nodeType\":\"FeatureLeaf\",\"isLeaf\":true,\"isCompoundFeature\":false,\"mixsetOrFileNode\":null}"
        + "],\"links\":["
        + "{\"sourceNodeId\":1,\"targetNodeId\":2,\"linkType\":\"FeatureLink\",\"opType\":\"Include\",\"isSub\":false},"
        + "{\"sourceNodeId\":1,\"targetNodeId\":3,\"linkType\":\"FeatureLink\",\"opType\":\"Exclude\",\"isSub\":false}"
        + "]}}";
    FeatureModel model = FeatureModel.fromJSON(json);
    Assert.assertEquals(2, model.numberOfFeaturelink());
    Assert.assertEquals(FeatureConnectingOpType.Include, model.getFeaturelink(0).getFeatureConnectingOpType());
    Assert.assertEquals(FeatureConnectingOpType.Exclude, model.getFeaturelink(1).getFeatureConnectingOpType());
  }

