  @Test
  public void fromJSON_compoundNodeChildIdNotFound()
  {
    // childFeatureIds references a node ID that doesn't exist — should not crash
    String json = "{\"featureModel\":{\"name\":\"M\",\"nodes\":["
        + "{\"id\":1,\"uniqueName\":\"P_1\",\"name\":\"P\",\"nodeType\":\"CompoundFeatureNode\",\"isLeaf\":false,\"isCompoundFeature\":true,\"childFeatureIds\":[999]}"
        + "],\"links\":[]}}";
    FeatureModel model = FeatureModel.fromJSON(json);
    Assert.assertNotNull(model);
    CompoundFeatureNode cfn = (CompoundFeatureNode) model.getNode(0);
    Assert.assertEquals(0, cfn.numberOfChildFeatures()); // 999 not found, skipped
  }

  @Test
  public void fromJSON_linkWithUnknownNodeIds()
  {
    // Link references node IDs that don't exist — should not crash
    String json = "{\"featureModel\":{\"name\":\"M\",\"nodes\":[],\"links\":["
        + "{\"sourceNodeId\":888,\"targetNodeId\":999,\"linkType\":\"FeatureLink\",\"opType\":\"Include\",\"isSub\":false}"
        + "]}}";
    FeatureModel model = FeatureModel.fromJSON(json);
    Assert.assertNotNull(model);
    Assert.assertEquals(1, model.numberOfFeaturelink());
    // Source and target should be null since IDs don't match any node
    Assert.assertFalse(model.getFeaturelink(0).hasSourceFeatureNode());
    Assert.assertFalse(model.getFeaturelink(0).hasTargetFeatureNode());
  }

  @Test
  public void fromJSON_mixsetOrFileNodeIsUmpleFileType()
  {
    // UmpleFile type is not reconstructed — leaf should have no mixsetOrFileNode
    String json = "{\"featureModel\":{\"name\":\"M\",\"nodes\":[{\"id\":1,\"uniqueName\":\"L\",\"name\":\"L\",\"nodeType\":\"FeatureLeaf\",\"isLeaf\":true,\"isCompoundFeature\":false,\"mixsetOrFileNode\":{\"type\":\"UmpleFile\",\"name\":\"test\",\"isMixset\":false,\"useUmpleFile\":null,\"useUmpleLine\":0}}],\"links\":[]}}";
    FeatureModel model = FeatureModel.fromJSON(json);
    FeatureLeaf leaf = (FeatureLeaf) model.getNode(0);
    Assert.assertFalse(leaf.hasMixsetOrFileNode());
  }

